@startuml
left to right direction
package "edu" {
  package "fiuba" {
    package "algoChess" {
      package "interfaz" {
        package "controladores" {
          class "AceptarNombresHandler" {
            + TFnombreJugador1 : TextField
            + TFnombreJugador2 : TextField
            + popupNombres : Popup
            + stage : Stage
            + AceptarNombresHandler()
            + handle()
          }
          class "AtacarPiezaHandler" {
            + stage : Stage
            + tFX : TextField
            + stage : Stage
            + AtacarPiezaHandler()
            + handle()
          }
          class "CancelarNombresHandler" {
            + popupNombres : Popup
            + stage : Stage
            + CancelarNombresHandler()
            + handle()
          }
          class "CrearPiezaHandler" {
            + head : HBox
            + nombrePieza : String
            + stageUbicar : Stage
            + x : TextField
            + y : TextField
            + CrearPiezaHandler()
            + handle()
          }
          class "CurarPiezaHandler" {
            + stage : Stage
            + tFX : TextField
            + tFY : TextField
            + CurarPiezaHandler()
            + handle()
          }
          class "IniciarJuegoOHandler" {
            + IniciarJuegoOHandler()
          }
          class "JugarHandler" {
            + stage : Stage
            + JugarHandler()
            + handle()
          }
          class "SalirHandler" {
            + handle()
          }
          class "UbicarPiezaHandler" {
            + head : HBox
            + listaPieza : HashMap<String, Class>
            + nombrePieza : String
            + stagePrincipal : Stage
            + stageUbicar : Stage
            + tFX : TextField
            + tFY : TextField
            + UbicarPiezaHandler()
            + alerta3seg()
            + handle()
          }
        }
      }
    }
  }
}
package "vista" {
  class "SegundaEtapa" {
    + SegundaEtapa()
  }
  class "PantallaPrincipal" {
    + PantallaPrincipal()
  }
  class "VistaTablero" {
    + VistaTablero()
  }
  class "VistaPieza" {
    + VistaPieza()
  }
}
package "modelo" {
  package "entidades" {
    class "Pieza" {
      + Pieza()
    }
    class "Curandero" {
      + Curandero()
    }
  }
  package "juego" {
    class "Juego" {
      + Juego()
    }
  }
  package "bandos" {
    class "Bando" {
      + Bando()
    }
  }
}
package "javafx" {
  class "EventHandler" {
    + EventHandler()
  }
}
"AceptarNombresHandler" ..|> "EventHandler"
"AtacarPiezaHandler" ..|> "EventHandler"
"CancelarNombresHandler" ..|> "EventHandler"
"CrearPiezaHandler" ..|> "EventHandler"
"CurarPiezaHandler" ..|> "EventHandler"
"IniciarJuegoOHandler" ..|> "EventHandler"
"JugarHandler" ..|> "EventHandler"
"SalirHandler" ..|> "EventHandler"
"UbicarPiezaHandler" ..|> "EventHandler"
"UbicarPiezaHandler" --> "VistaPieza" : mapView
"UbicarPiezaHandler" --> "VistaPieza" : pieceView
"UbicarPiezaHandler" --> "Juego" : emisor
"UbicarPiezaHandler" --> "Bando" : bandoPieza
"CrearPiezaHandler" --> "VistaPieza" : pantallaPrincipal
"CrearPiezaHandler" --> "Juego" : segundaEtapa
"CrearPiezaHandler" --> "Bando" : segundaEtapa
"AtacarPiezaHandler" --> "VistaPieza" : pantallaPrincipal
"AtacarPiezaHandler" --> "Juego" : segundaEtapa
"CancelarNombresHandler" --> "SegundaEtapa" : segundaEtapa
"JugarHandler" --> "VistaTablero" : pantallaPrincipal
"JugarHandler" --> "Juego" : juego
"JugarHandler" --> "Bando" : juego
"SalirHandler" --> "VistaPieza" : emisor
"SalirHandler" --> "Juego" : juego
@enduml
